package pl.msurvival.core;
import org.bukkit.ChatColor;import org.bukkit.command.*;import org.bukkit.plugin.java.JavaPlugin;
public final class MSurvivalCore extends JavaPlugin{public void onEnable(){saveDefaultConfig();} public boolean onCommand(CommandSender s,Command c,String l,String[] a){if(!s.hasPermission("msurvival.core.admin")){s.sendMessage(color(getConfig().getString("messages.prefix")+getConfig().getString("messages.no-permission")));return true;}reloadConfig();s.sendMessage(color(getConfig().getString("messages.prefix")+getConfig().getString("messages.reload")));return true;} public static String color(String t){return ChatColor.translateAlternateColorCodes('&',t==null?"":t);} }
